import {
  ButtonLink,
  ButtonSizes,
  ButtonVariants,
  Dropdown,
  H2,
  Icon,
  LastUpdated,
  Layout,
  P,
} from 'components';
import { colors, icons, typography } from 'core';
import { NextComponentType } from 'next';
import { ApolloPageContext } from 'next-with-apollo';
import { useRouter } from 'next/router';
import React, { useEffect } from 'react';

import { Article, ArticleVariables } from '../ArticlePage/__generated__/Article';
import { queryArticle } from '../ArticlePage/graphql';
import { InitProps, Props } from './props';

export const QuestionPage: NextComponentType<ApolloPageContext, InitProps, Props> = (
  props: Props,
) => {
  const { data } = props;
  const router = useRouter();

  useEffect(() => {
    if (!data.data?.article) router.push('/allQuestions');
  }, [data.data?.article, router]);

  return (
    <Layout
      headerButtons={props.data?.data?.headerButtons}
      footerSections={props.data?.data?.footerSections}
      headerLinks={props.data?.data?.headerLinks}
    >
      <div className="container mt-3 tw-mb-8">
        <ButtonLink
          href={props.data?.data?.artilcesPageBackButton?.backButton?.link}
          variant={ButtonVariants.Flat}
          size={ButtonSizes.Small}
          className="pl-0"
        >
          <Icon
            icon={icons.arrows.keyboardArrowLeft}
            color={colors.variants.Neutral.Black}
            className="mr-1"
          />
          <P
            color={colors.variants.Neutral.Grey}
            typography={typography.variants.Element.Regular12}
          >
            {props.data?.data?.artilcesPageBackButton?.backButton?.title}
          </P>
        </ButtonLink>
        <H2 className="mb-2">Введение в вакцинацию</H2>
        <LastUpdated />

        <Dropdown abc="fgfgfg" />
        <Dropdown abc="fgfgfg" />
      </div>
    </Layout>
  );
};

QuestionPage.getInitialProps = async (ctx) => {
  const id = ctx.query?.id.toString();
  const lang = ctx.req?.headers?.cookie?.match(/(kk-Cyrl-KZ|ru-RU)/)?.[0] || 'ru-RU';

  const data = await ctx.apolloClient.query<Article, ArticleVariables>({
    query: queryArticle,
    variables: { id, locale: lang },
  });
  return { data };
};
